import heapq, random
random.seed(7)
N = {N}
# K sorted streams, total N items, heap-based k-way merge -> O(N log K)
K = 8
streams = [[] for _ in range(K)]
for i in range(N):
    streams[i % K].append(i)  # each stream already ascending
heap = []
for si, s in enumerate(streams):
    if s:
        heapq.heappush(heap, (s[0], si, 0))
merged = 0
while heap:
    val, si, pos = heapq.heappop(heap)
    merged += 1
    if pos + 1 < len(streams[si]):
        heapq.heappush(heap, (streams[si][pos + 1], si, pos + 1))
print(merged)
